content.content:
input, select { background: #0f3460; color: #e0e0e0; border: 1px solid #1a4a8a; border-radius: 4px; padding: 4px 8px; font-size: 12px; font-family: inherit; }
.stats { color: #6080a0; font-size: 11px; margin-left: auto; }
table { border-collapse: collapse; min-width: 100%; }
thead { position: sticky; top: 49px; z-index: 50; }
th { background: #0f3460; color: #80b0e0; padding: 7px 10px; text-align: right; cursor: pointer; white-space: nowrap; border: 1px solid #1a4a8a; user-select: none; }
th:hover { background: #1a4a8a; }
th.sort-asc::after { content: " ▲"; color: #ffd700; }
th.sort-desc::after { content: " ▼"; color: #ffd700; }
th:first-child, th:nth-child(2), th:nth-child(3), th:nth-child(4) { text-align: left; }
td { padding: 5px 10px; border: 1px solid #1a2a4a; text-align: right; white-space: nowrap; }
